   179→    pub kits_removed: Vec<String>,
   180→    /// Total files deleted (vvx binaries, brand file)
   181→    pub files_deleted: u32,
   182→    /// Commands removed from .claude/commands/
   183→    pub commands_removed: u32,
   184→    /// Hooks removed from .claude/hooks/
   185→    pub hooks_removed: u32,
   186→    /// CLAUDE.md sections collapsed
   187→    pub claude_sections_collapsed: Vec<String>,
   188→}
   189→
   190→// =============================================================================
   191→// Public Functions
   192→// =============================================================================
   193→
   194→/// Install kit assets from parcel to target repo.
   195→/// Nuclear install: deletes existing installation before copying fresh.
   196→///
   197→/// # Arguments
   198→/// * `args` - Emplace arguments (parcel dir and burc.env path)
   199→///
   200→/// # Returns
   201→/// EmplaceResult with installation summary, or error message
   202→pub fn vofe_emplace(args: &vofe_EmplaceArgs) -> Result<vofe_EmplaceResult, String> {
   203→    eprintln!("emplace: installing kit assets...");
   204→    eprintln!("  parcel: {}", args.parcel_dir.display());
   205→    eprintln!("  burc: {}", args.burc_path.display());
   206→
   207→    // 1. Parse BURC (resolves paths relative to burc.env location)
   208→    let burc = zvofe_parse_burc(&args.burc_path)?;
   209→
   210→    // 2. Validate git state
   211→    zvofe_check_is_git_repo(&burc.project_root)?;
   212→    zvofe_check_git_clean(&burc.project_root)?;
   213→
   214→    // 3. Read brand identity
   215→    let brand_path = args.parcel_dir.join("vvbf_brand.json");
   216→    let (hallmark, kit_ids) = zvofe_read_brand(&brand_path)?;
   217→
   218→    // 4. Validate exact match between parcel kits and target BURC_MANAGED_KITS
   219→    let mut burc_kits_sorted = burc.managed_kits.clone();
   220→    let mut brand_kits_sorted = kit_ids.clone();
   221→    burc_kits_sorted.sort();
   222→    brand_kits_sorted.sort();
   223→
   224→    if burc_kits_sorted != brand_kits_sorted {
   225→        return Err(format!(
   226→            "Kit mismatch: parcel contains [{}] but target expects [{}]",
   227→            kit_ids.join(","),
   228→            burc.managed_kits.join(",")
   229→        ));
   230→    }
   231→
   232→    // 5. Nuclear cleanup - delete existing .vvk/ and kit directories
   233→    let vvk_dir = burc.project_root.join(".vvk");
   234→    if vvk_dir.exists() {
   235→        fs::remove_dir_all(&vvk_dir)
   236→            .map_err(|e| format!("Failed to remove .vvk directory: {}", e))?;
   237→    }
   238→
   239→    for kit_id in &kit_ids {
   240→        let kit_dir = burc.tools_dir.join(kit_id);
   241→        if kit_dir.exists() {
   242→            fs::remove_dir_all(&kit_dir)
   243→                .map_err(|e| format!("Failed to remove kit directory {}: {}", kit_id, e))?;
   244→        }
   245→    }
   246→
   247→    // 6. Create .vvk/ and copy brand file
   248→    fs::create_dir_all(&vvk_dir)
   249→        .map_err(|e| format!("Failed to create .vvk directory: {}", e))?;
   250→
   251→    let brand_dest = vvk_dir.join("vvbf_brand.json");
   252→    fs::copy(&brand_path, &brand_dest)
   253→        .map_err(|e| format!("Failed to copy brand file: {}", e))?;
   254→
   255→    // 7. Copy kit assets and route special files
   256→    let mut total_files = 0u32;
   257→    let mut commands_routed = 0u32;
   258→    let mut hooks_routed = 0u32;
   259→
   260→    let kits_dir = args.parcel_dir.join("kits");
   261→    for kit_id in &kit_ids {
   262→        let kit_source = kits_dir.join(kit_id);
   263→        let kit_dest = burc.tools_dir.join(kit_id);
   264→
   265→        if !kit_source.exists() {
   266→            return Err(format!("Kit not found in parcel: {}", kit_id));
   267→        }
   268→
   269→        let (files, cmds, hks) = zvofe_copy_kit(
   270→            &kit_source,
   271→            &kit_dest,
   272→            &burc.project_root,
   273→            kit_id,
   274→        )?;
   275→
   276→        total_files += files;
   277→        commands_routed += cmds;
   278→        hooks_routed += hks;
   279→    }
   280→
   281→    // 7b. Route Claude config assets from parcel claude/* to target .claude/*
   282→    let (parcel_cmds, parcel_hks) = zvofe_route_claude_assets(&args.parcel_dir, &burc.project_root)?;
   283→    total_files += parcel_cmds + parcel_hks;
   284→    commands_routed += parcel_cmds;
   285→    hooks_routed += parcel_hks;
   286→
   287→    // 8. Freshen CLAUDE.md with kit sections
   288→    let sections = zvofe_read_templates(&args.parcel_dir, &kit_ids)?;
   289→    let section_tags: Vec<String> = sections.iter().map(|s| s.tag.clone()).collect();
   290→
   291→    let claude_path = burc.project_root.join("CLAUDE.md");
   292→    zvofe_freshen_claude(&claude_path, &sections)?;
   293→
   294→    // 9. Commit installation
   295→    let commit_msg = format!("VVK install: hallmark {}", hallmark);
   296→    zvofe_git_commit(&burc.project_root, &commit_msg)?;
   297→
   298→    eprintln!("emplace: success - {} files, {} commands, {} hooks", total_files, commands_routed, hooks_routed);
   299→
   300→    Ok(vofe_EmplaceResult {
   301→        hallmark,
   302→        kits_installed: kit_ids,
   303→        files_copied: total_files,
   304→        commands_routed,
   305→        hooks_routed,
   306→        claude_sections_updated: section_tags,
   307→    })
   308→}
   309→
   310→/// Remove kit assets from target repo.
   311→///
   312→/// # Arguments
   313→/// * `args` - Vacate arguments (burc.env path)
   314→///
   315→/// # Returns
   316→/// VacateResult with removal summary, or error message
   317→pub fn vofe_vacate(args: &vofe_VacateArgs) -> Result<vofe_VacateResult, String> {
   318→    eprintln!("vacate: removing kit assets...");
   319→    eprintln!("  burc: {}", args.burc_path.display());
   320→
   321→    // 1. Parse BURC
   322→    let burc = zvofe_parse_burc(&args.burc_path)?;
   323→
   324→    // 2. Validate git state
   325→    zvofe_check_git_clean(&burc.project_root)?;
   326→
   327→    // 3. Read brand file from .vvk/
   328→    let brand_path = burc.project_root.join(".vvk").join("vvbf_brand.json");
   329→    if !brand_path.exists() {
   330→        return Err("No VVK installation found (.vvk/vvbf_brand.json missing)".to_string());
   331→    }
   332→    let (_hallmark, kit_ids) = zvofe_read_brand(&brand_path)?;
   333→
   334→    // 4. Remove commands and hooks
   335→    let mut total_files = 0u32;
   336→    let mut commands_removed = 0u32;
   337→    let mut hooks_removed = 0u32;
   338→
   339→    let commands_dir = burc.project_root.join(".claude").join("commands");
   340→    let hooks_dir = burc.project_root.join(".claude").join("hooks");
   341→
   342→    for kit_id in &kit_ids {
   343→        // Get cipher from kit_id (e.g., "jjk" -> "jj")
   344→        let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
   345→
   346→        // Remove commands matching {cipher}c-*.md
   347→        if commands_dir.exists() {
   348→            commands_removed += zvofe_remove_matching_files(&commands_dir, cipher, true)?;
   349→        }
   350→
   351→        // Remove hooks matching {cipher}h_*
   352→        if hooks_dir.exists() {
   353→            hooks_removed += zvofe_remove_matching_files(&hooks_dir, cipher, false)?;
   354→        }
   355→    }
   356→
   357→    // 5. Collapse CLAUDE.md sections (get tags from registry)
   358→    let section_tags: Vec<String> = kit_ids
   359→        .iter()
   360→        .filter_map(|kit_id| vofc_find_kit_by_id(kit_id))
   361→        .flat_map(|kit| kit.managed_sections.iter().map(|s| s.tag.to_string()))
   362→        .collect();
   363→
   364→    let claude_path = burc.project_root.join("CLAUDE.md");
   365→    zvofe_collapse_claude(&claude_path, &section_tags)?;
   366→
   367→    // 6. Delete vvx binary from Tools/vvk/bin/
   368→    // Kit directories are intentionally preserved (open-source utilities)
   369→    let vvk_bin_dir = burc.tools_dir.join("vvk").join("bin");
   370→    if vvk_bin_dir.exists() {
   371→        let entries = fs::read_dir(&vvk_bin_dir)
   372→            .map_err(|e| format!("Failed to read vvk bin dir: {}", e))?;
   373→
   374→        for entry in entries {
   375→            let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   376→            let path = entry.path();
   377→            let file_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
   378→
   379→            // Remove vvx binaries (vvx-darwin-arm64, vvx-linux-x86_64, etc.)
   380→            if file_name.starts_with("vvx") {
   381→                fs::remove_file(&path)
   382→                    .map_err(|e| format!("Failed to remove vvx binary {}: {}", path.display(), e))?;
   383→                total_files += 1;
   384→                eprintln!("  removed: {}", path.display());
   385→            }
   386→        }
   387→    }
   388→
   389→    // 7. Delete brand file and .vvk/
   390→    fs::remove_file(&brand_path)
   391→        .map_err(|e| format!("Failed to remove brand file: {}", e))?;
   392→
   393→    let vvk_dir = burc.project_root.join(".vvk");
   394→    if vvk_dir.exists() {
   395→        // Remove .vvk/ directory
   396→        let _ = fs::remove_dir(&vvk_dir);
   397→    }
   398→
   399→    // 8. Commit uninstallation
   400→    zvofe_git_commit(&burc.project_root, "VVK uninstall")?;
   401→
   402→    eprintln!("vacate: success - {} files, {} commands, {} hooks removed", total_files, commands_removed, hooks_removed);
   403→
   404→    Ok(vofe_VacateResult {
   405→        kits_removed: kit_ids,
   406→        files_deleted: total_files,
   407→        commands_removed,
   408→        hooks_removed,
   409→        claude_sections_collapsed: section_tags,
   410→    })
   411→}
