   413→// =============================================================================
   414→// Internal Functions (zvofe_*)
   415→// =============================================================================
   416→
   417→/// Parse burc.env file to extract environment variables.
   418→/// BURC_PROJECT_ROOT is the path from burc.env's location to the project root.
   419→/// BURC_TOOLS_DIR is resolved relative to the resolved project_root (per BURC spec).
   420→fn zvofe_parse_burc(path: &Path) -> Result<vofe_BurcEnv, String> {
   421→    if !path.exists() {
   422→        return Err(format!("burc.env not found: {}", path.display()));
   423→    }
   424→
   425→    // Get the parent directory of burc.env for path resolution
   426→    let burc_parent = path
   427→        .parent()
   428→        .ok_or_else(|| "burc.env path has no parent directory".to_string())?;
   429→
   430→    let content = fs::read_to_string(path)
   431→        .map_err(|e| format!("Failed to read burc.env: {}", e))?;
   432→
   433→    let mut vars: HashMap<String, String> = HashMap::new();
   434→
   435→    for line in content.lines() {
   436→        let line = line.trim();
   437→
   438→        // Skip comments and empty lines
   439→        if line.is_empty() || line.starts_with('#') {
   440→            continue;
   441→        }
   442→
   443→        // Parse KEY=VALUE (handle quoted values)
   444→        if let Some(eq_pos) = line.find('=') {
   445→            let key = line[..eq_pos].trim();
   446→            let mut value = line[eq_pos + 1..].trim();
   447→
   448→            // Remove surrounding quotes if present
   449→            if (value.starts_with('"') && value.ends_with('"'))
   450→                || (value.starts_with('\'') && value.ends_with('\''))
   451→            {
   452→                value = &value[1..value.len() - 1];
   453→            }
   454→
   455→            vars.insert(key.to_string(), value.to_string());
   456→        }
   457→    }
   458→
   459→    let tools_dir_str = vars
   460→        .get("BURC_TOOLS_DIR")
   461→        .ok_or_else(|| "burc.env missing required variable: BURC_TOOLS_DIR".to_string())?;
   462→
   463→    let project_root_str = vars
   464→        .get("BURC_PROJECT_ROOT")
   465→        .ok_or_else(|| "burc.env missing required variable: BURC_PROJECT_ROOT".to_string())?;
   466→
   467→    // BURC_PROJECT_ROOT is the path from burc.env's location to project root
   468→    let project_root = burc_parent.join(project_root_str);
   469→    let project_root = project_root
   470→        .canonicalize()
   471→        .map_err(|e| format!("BURC_PROJECT_ROOT path invalid ({}): {}", project_root.display(), e))?;
   472→
   473→    // Resolve tools_dir relative to project_root (per BURC spec)
   474→    let tools_dir = project_root.join(tools_dir_str);
   475→    let tools_dir = tools_dir
   476→        .canonicalize()
   477→        .map_err(|e| format!("BURC_TOOLS_DIR path invalid ({}): {}", tools_dir.display(), e))?;
   478→
   479→    // Parse BURC_MANAGED_KITS (comma-separated list)
   480→    let managed_kits_str = vars
   481→        .get("BURC_MANAGED_KITS")
   482→        .ok_or_else(|| "burc.env missing required variable: BURC_MANAGED_KITS".to_string())?;
   483→
   484→    let managed_kits: Vec<String> = managed_kits_str
   485→        .split(',')
   486→        .map(|s| s.trim().to_string())
   487→        .filter(|s| !s.is_empty())
   488→        .collect();
   489→
   490→    if managed_kits.is_empty() {
   491→        return Err("BURC_MANAGED_KITS must specify at least one kit".to_string());
   492→    }
   493→
   494→    Ok(vofe_BurcEnv {
   495→        tools_dir,
   496→        project_root,
   497→        managed_kits,
   498→    })
   499→}
   500→
   501→/// Read brand file and extract hallmark and kit list.
   502→fn zvofe_read_brand(path: &Path) -> Result<(u32, Vec<String>), String> {
   503→    if !path.exists() {
   504→        return Err(format!("Brand file not found: {}", path.display()));
   505→    }
   506→
   507→    let content = fs::read_to_string(path)
   508→        .map_err(|e| format!("Failed to read brand file: {}", e))?;
   509→
   510→    let json: serde_json::Value = serde_json::from_str(&content)
   511→        .map_err(|e| format!("Failed to parse brand JSON: {}", e))?;
   512→
   513→    let hallmark = json
   514→        .get(VOFE_BRAND_HALLMARK)
   515→        .and_then(|v| v.as_u64())
   516→        .map(|v| v as u32)
   517→        .ok_or_else(|| "Brand file missing hallmark".to_string())?;
   518→
   519→    let kits = json
   520→        .get(VOFE_BRAND_KITS)
   521→        .and_then(|v| v.as_array())
   522→        .ok_or_else(|| "Brand file missing kits array".to_string())?;
   523→
   524→    let kit_ids: Vec<String> = kits
   525→        .iter()
   526→        .filter_map(|v| v.as_str().map(String::from))
   527→        .collect();
   528→
   529→    if kit_ids.is_empty() {
   530→        return Err("Brand file has empty kits array".to_string());
   531→    }
   532→
   533→    Ok((hallmark, kit_ids))
   534→}
   535→
   536→/// Copy a kit directory and route special files.
   537→/// Returns (files_copied, commands_routed, hooks_routed).
   538→fn zvofe_copy_kit(
   539→    source: &Path,
   540→    dest: &Path,
   541→    project_root: &Path,
   542→    kit_id: &str,
   543→) -> Result<(u32, u32, u32), String> {
   544→    let mut files = 0u32;
   545→    let mut commands = 0u32;
   546→    let mut hooks = 0u32;
   547→
   548→    // Get cipher from kit_id (e.g., "jjk" -> "jj")
   549→    let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
   550→
   551→    // Walk source directory
   552→    let entries = zvofe_walk_dir(source)?;
   553→
   554→    for entry in entries {
   555→        let rel_path = entry
   556→            .strip_prefix(source)
   557→            .map_err(|e| format!("Path strip failed: {}", e))?;
   558→
   559→        let file_name = rel_path
   560→            .file_name()
   561→            .and_then(|n| n.to_str())
   562→            .unwrap_or("");
   563→
   564→        // Determine destination based on file type
   565→        let dest_path = if zvofe_is_command_file(file_name, cipher) {
   566→            // Route commands to .claude/commands/
   567→            let commands_dir = project_root.join(".claude").join("commands");
   568→            fs::create_dir_all(&commands_dir)
   569→                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
   570→            commands += 1;
   571→            commands_dir.join(file_name)
   572→        } else if zvofe_is_hook_file(file_name, cipher) {
   573→            // Route hooks to .claude/hooks/
   574→            let hooks_dir = project_root.join(".claude").join("hooks");
   575→            fs::create_dir_all(&hooks_dir)
   576→                .map_err(|e| format!("Failed to create hooks dir: {}", e))?;
   577→            hooks += 1;
   578→            hooks_dir.join(file_name)
   579→        } else {
   580→            // Default: preserve relative path in kit directory
   581→            dest.join(rel_path)
   582→        };
   583→
   584→        // Create parent directories
   585→        if let Some(parent) = dest_path.parent() {
   586→            fs::create_dir_all(parent)
   587→                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
   588→        }
   589→
   590→        // Copy file
   591→        fs::copy(&entry, &dest_path)
   592→            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest_path.display(), e))?;
   593→
   594→        files += 1;
   595→    }
   596→
   597→    Ok((files, commands, hooks))
   598→}
   599→
   600→/// Walk directory recursively, returning all file paths.
   601→fn zvofe_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
   602→    let mut files = Vec::new();
   603→
   604→    if !dir.is_dir() {
   605→        return Ok(files);
   606→    }
   607→
   608→    let entries = fs::read_dir(dir)
   609→        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
   610→
   611→    for entry in entries {
   612→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   613→        let path = entry.path();
   614→
   615→        if path.is_dir() {
   616→            files.extend(zvofe_walk_dir(&path)?);
   617→        } else {
   618→            files.push(path);
   619→        }
   620→    }
   621→
   622→    Ok(files)
   623→}
   624→
   625→/// Check if file is a command file (matches {cipher}c-*.md pattern).
   626→fn zvofe_is_command_file(file_name: &str, cipher: &str) -> bool {
   627→    let prefix = format!("{}{}", cipher, VOFC_COMMAND_SIGNET_SUFFIX);
   628→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
   629→}
   630→
   631→/// Check if file is a hook file (matches {cipher}h-*.md pattern).
   632→fn zvofe_is_hook_file(file_name: &str, cipher: &str) -> bool {
   633→    let prefix = format!("{}{}", cipher, VOFC_HOOK_SIGNET_SUFFIX);
   634→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
   635→}
   636→
   637→/// Route Claude config assets from parcel claude/* to target .claude/*.
   638→/// Returns (commands_routed, hooks_routed).
   639→fn zvofe_route_claude_assets(
   640→    parcel_dir: &Path,
   641→    project_root: &Path,
   642→) -> Result<(u32, u32), String> {
   643→    let mut commands_count = 0u32;
   644→    let mut hooks_count = 0u32;
   645→
   646→    // Route commands from parcel claude/commands/ to target .claude/commands/
   647→    let commands_source = parcel_dir.join("claude").join("commands");
   648→    if commands_source.exists() {
   649→        let commands_dest = project_root.join(".claude").join("commands");
   650→        fs::create_dir_all(&commands_dest)
   651→            .map_err(|e| format!("Failed to create .claude/commands dir: {}", e))?;
   652→
   653→        commands_count = zvofe_copy_all_files(&commands_source, &commands_dest)?;
   654→    }
   655→
   656→    // Route hooks from parcel claude/hooks/ to target .claude/hooks/
   657→    let hooks_source = parcel_dir.join("claude").join("hooks");
   658→    if hooks_source.exists() {
   659→        let hooks_dest = project_root.join(".claude").join("hooks");
   660→        fs::create_dir_all(&hooks_dest)
   661→            .map_err(|e| format!("Failed to create .claude/hooks dir: {}", e))?;
   662→
   663→        hooks_count = zvofe_copy_all_files(&hooks_source, &hooks_dest)?;
   664→    }
   665→
   666→    Ok((commands_count, hooks_count))
   667→}
   668→
   669→/// Copy all files from source directory to dest directory.
   670→/// Returns count of files copied.
   671→fn zvofe_copy_all_files(source_dir: &Path, dest_dir: &Path) -> Result<u32, String> {
   672→    let mut count = 0u32;
   673→
   674→    let entries = fs::read_dir(source_dir)
   675→        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
   676→
   677→    for entry in entries {
   678→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   679→        let path = entry.path();
   680→
   681→        if !path.is_file() {
   682→            continue;
   683→        }
   684→
   685→        let file_name = path
   686→            .file_name()
   687→            .ok_or_else(|| format!("No file name for {}", path.display()))?;
   688→
   689→        let dest_path = dest_dir.join(file_name);
   690→        fs::copy(&path, &dest_path)
   691→            .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
   692→        count += 1;
   693→    }
   694→
   695→    Ok(count)
   696→}
