   698→/// Read managed section templates from parcel.
   699→fn zvofe_read_templates(
   700→    parcel_dir: &Path,
   701→    kit_ids: &[String],
   702→) -> Result<Vec<voff_ManagedSection>, String> {
   703→    let mut sections = Vec::new();
   704→
   705→    for kit_id in kit_ids {
   706→        let kit = vofc_find_kit_by_id(kit_id)
   707→            .ok_or_else(|| format!("Kit not in registry: {}", kit_id))?;
   708→
   709→        let templates_dir = parcel_dir.join("kits").join(kit_id).join("templates");
   710→
   711→        for section in kit.managed_sections {
   712→            let template_path = templates_dir.join(section.template_path);
   713→            if !template_path.exists() {
   714→                return Err(format!(
   715→                    "Template not found in parcel: {}",
   716→                    template_path.display()
   717→                ));
   718→            }
   719→
   720→            let content = fs::read_to_string(&template_path)
   721→                .map_err(|e| format!("Failed to read template {}: {}", section.template_path, e))?;
   722→
   723→            sections.push(voff_ManagedSection {
   724→                tag: section.tag.to_string(),
   725→                content,
   726→            });
   727→        }
   728→    }
   729→
   730→    Ok(sections)
   731→}
   732→
   733→/// Freshen CLAUDE.md with managed sections.
   734→fn zvofe_freshen_claude(
   735→    claude_path: &Path,
   736→    sections: &[voff_ManagedSection],
   737→) -> Result<(), String> {
   738→    // Read existing content or start with empty
   739→    let content = if claude_path.exists() {
   740→        fs::read_to_string(claude_path)
   741→            .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?
   742→    } else {
   743→        "# Claude Code Project Memory\n".to_string()
   744→    };
   745→
   746→    // Freshen with new sections
   747→    let result = voff_freshen(&content, sections);
   748→
   749→    // Write back
   750→    fs::write(claude_path, &result.content)
   751→        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
   752→
   753→    Ok(())
   754→}
   755→
   756→/// Collapse CLAUDE.md managed sections to UNINSTALLED markers.
   757→fn zvofe_collapse_claude(claude_path: &Path, tags: &[String]) -> Result<(), String> {
   758→    if !claude_path.exists() {
   759→        return Ok(()); // Nothing to collapse
   760→    }
   761→
   762→    let content = fs::read_to_string(claude_path)
   763→        .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?;
   764→
   765→    let tag_refs: Vec<&str> = tags.iter().map(|s| s.as_str()).collect();
   766→    let collapsed = voff_collapse(&content, &tag_refs);
   767→
   768→    fs::write(claude_path, &collapsed)
   769→        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
   770→
   771→    Ok(())
   772→}
