   774→/// Remove files matching a pattern from a directory.
   775→/// If is_command is true, matches {cipher}c-*.md; otherwise matches {cipher}h_*
   776→/// Returns count of files removed.
   777→fn zvofe_remove_matching_files(dir: &Path, cipher: &str, is_command: bool) -> Result<u32, String> {
   778→    let mut count = 0u32;
   779→
   780→    let entries = fs::read_dir(dir)
   781→        .map_err(|e| format!("Failed to read directory {}: {}", dir.display(), e))?;
   782→
   783→    for entry in entries {
   784→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   785→        let path = entry.path();
   786→
   787→        if !path.is_file() {
   788→            continue;
   789→        }
   790→
   791→        let file_name = path
   792→            .file_name()
   793→            .and_then(|n| n.to_str())
   794→            .unwrap_or("");
   795→
   796→        let matches = if is_command {
   797→            zvofe_is_command_file(file_name, cipher)
   798→        } else {
   799→            zvofe_is_hook_file(file_name, cipher)
   800→        };
   801→
   802→        if matches {
   803→            fs::remove_file(&path)
   804→                .map_err(|e| format!("Failed to remove {}: {}", path.display(), e))?;
   805→            count += 1;
   806→        }
   807→    }
   808→
   809→    Ok(count)
   810→}
