     5→//! CLAUDE.md Managed Section Freshening
     6→//!
     7→//! Provides utilities for managing CLAUDE.md sections during kit install/uninstall.
     8→//!
     9→//! Marker format:
    10→//! - `<!-- MANAGED:{TAG}:BEGIN -->` ... content ... `<!-- MANAGED:{TAG}:END -->`
    11→//! - `<!-- MANAGED:{TAG}:UNINSTALLED -->` (placeholder preserving position)
    12→//!
    13→//! Rules:
    14→//! - Content between BEGIN/END markers is replaced entirely on install
    15→//! - User content outside markers is preserved
    16→//! - UNINSTALLED markers expand back to BEGIN/END at same location
    17→//! - Missing markers → append section at end of file
    18→
    19→use std::collections::HashMap;
    20→
    21→/// A managed section to be installed or updated.
    22→#[derive(Debug, Clone)]
    23→pub struct voff_ManagedSection {
    24→    /// Tag identifier (e.g., "JJK", "CMK", "JJK_GALLOPS")
    25→    pub tag: String,
    26→    /// Content to place between markers (excluding the markers themselves)
    27→    pub content: String,
    28→}
    29→
    30→/// Result of freshening a CLAUDE.md file.
    31→#[derive(Debug)]
    32→pub struct voff_FreshenResult {
    33→    /// The freshened content
    34→    pub content: String,
    35→    /// Tags that were updated (had existing markers)
    36→    pub updated: Vec<String>,
    37→    /// Tags that were expanded from UNINSTALLED markers
    38→    pub expanded: Vec<String>,
    39→    /// Tags that were appended (no prior markers)
    40→    pub appended: Vec<String>,
    41→}
    42→
    43→/// Freshen CLAUDE.md content by updating managed sections.
    44→///
    45→/// # Arguments
    46→/// * `content` - Current CLAUDE.md content
    47→/// * `sections` - Sections to install, in order (order determines append order)
    48→///
    49→/// # Returns
    50→/// Result containing freshened content and change summary
    51→pub fn voff_freshen(content: &str, sections: &[voff_ManagedSection]) -> voff_FreshenResult {
    52→    let mut result = content.to_string();
    53→    let mut updated = Vec::new();
    54→    let mut expanded = Vec::new();
    55→    let mut appended = Vec::new();
    56→
    57→    for section in sections {
    58→        let begin_marker = format!("<!-- MANAGED:{}:BEGIN -->", section.tag);
    59→        let end_marker = format!("<!-- MANAGED:{}:END -->", section.tag);
    60→        let uninstalled_marker = format!("<!-- MANAGED:{}:UNINSTALLED -->", section.tag);
    61→
    62→        if let Some(replacement) = zvoff_replace_between_markers(&result, &begin_marker, &end_marker, &section.content) {
    63→            // Found existing BEGIN/END markers - replace content
    64→            result = replacement;
    65→            updated.push(section.tag.clone());
    66→        } else if let Some(expansion) = zvoff_expand_uninstalled(&result, &uninstalled_marker, &begin_marker, &end_marker, &section.content) {
    67→            // Found UNINSTALLED marker - expand it
    68→            result = expansion;
    69→            expanded.push(section.tag.clone());
    70→        } else {
    71→            // No markers found - append at end
    72→            result = zvoff_append_section(&result, &begin_marker, &end_marker, &section.content);
    73→            appended.push(section.tag.clone());
    74→        }
    75→    }
    76→
    77→    voff_FreshenResult {
    78→        content: result,
    79→        updated,
    80→        expanded,
    81→        appended,
    82→    }
    83→}
    84→
    85→/// Collapse managed sections to UNINSTALLED markers for uninstall.
    86→///
    87→/// # Arguments
    88→/// * `content` - Current CLAUDE.md content
    89→/// * `tags` - Tags to collapse
    90→///
    91→/// # Returns
    92→/// Content with sections collapsed to UNINSTALLED markers
    93→pub fn voff_collapse(content: &str, tags: &[&str]) -> String {
    94→    let mut result = content.to_string();
    95→
    96→    for tag in tags {
    97→        let begin_marker = format!("<!-- MANAGED:{}:BEGIN -->", tag);
    98→        let end_marker = format!("<!-- MANAGED:{}:END -->", tag);
    99→        let uninstalled_marker = format!("<!-- MANAGED:{}:UNINSTALLED -->", tag);
   100→
   101→        if let Some(collapsed) = zvoff_collapse_to_uninstalled(&result, &begin_marker, &end_marker, &uninstalled_marker) {
   102→            result = collapsed;
   103→        }
   104→    }
   105→
   106→    result
   107→}
   108→
   109→/// Parse existing managed sections from CLAUDE.md content.
   110→///
   111→/// # Returns
   112→/// Map of tag -> (start_line, end_line, is_uninstalled)
   113→pub fn voff_parse_sections(content: &str) -> HashMap<String, (usize, usize, bool)> {
   114→    let mut sections = HashMap::new();
   115→    let lines: Vec<&str> = content.lines().collect();
   116→
   117→    let mut i = 0;
   118→    while i < lines.len() {
   119→        let line = lines[i];
   120→
   121→        // Check for UNINSTALLED marker
   122→        if let Some(tag) = zvoff_parse_uninstalled_marker(line) {
   123→            sections.insert(tag, (i, i, true));
   124→            i += 1;
   125→            continue;
   126→        }
   127→
   128→        // Check for BEGIN marker
   129→        if let Some(tag) = zvoff_parse_begin_marker(line) {
   130→            // Find matching END marker
   131→            let mut j = i + 1;
   132→            while j < lines.len() {
   133→                if zvoff_parse_end_marker(lines[j]) == Some(tag.clone()) {
   134→                    sections.insert(tag, (i, j, false));
   135→                    break;
   136→                }
   137→                j += 1;
   138→            }
   139→            i = j + 1;
   140→            continue;
   141→        }
   142→
   143→        i += 1;
   144→    }
   145→
   146→    sections
   147→}
   148→
   149→// =============================================================================
   150→// Internal Functions (zvoff_*)
   151→// =============================================================================
   152→
   153→/// Replace content between BEGIN and END markers.
   154→fn zvoff_replace_between_markers(content: &str, begin: &str, end: &str, new_content: &str) -> Option<String> {
   155→    let begin_pos = content.find(begin)?;
   156→    let end_pos = content.find(end)?;
   157→
   158→    if end_pos <= begin_pos {
   159→        return None;
   160→    }
   161→
   162→    let before = &content[..begin_pos + begin.len()];
   163→    let after = &content[end_pos..];
   164→
   165→    // Ensure proper newlines around content
   166→    let formatted_content = if new_content.is_empty() {
   167→        "\n".to_string()
   168→    } else if new_content.starts_with('\n') {
   169→        format!("{}\n", new_content)
   170→    } else {
   171→        format!("\n{}\n", new_content)
   172→    };
   173→
   174→    Some(format!("{}{}{}", before, formatted_content, after))
   175→}
   176→
   177→/// Expand an UNINSTALLED marker to full BEGIN/END markers with content.
   178→fn zvoff_expand_uninstalled(content: &str, uninstalled: &str, begin: &str, end: &str, new_content: &str) -> Option<String> {
   179→    let pos = content.find(uninstalled)?;
   180→
   181→    let before = &content[..pos];
   182→    let after = &content[pos + uninstalled.len()..];
   183→
   184→    // Format the expanded section
   185→    let formatted_content = if new_content.is_empty() {
   186→        format!("{}\n{}", begin, end)
   187→    } else if new_content.starts_with('\n') {
   188→        format!("{}{}\n{}", begin, new_content, end)
   189→    } else {
   190→        format!("{}\n{}\n{}", begin, new_content, end)
   191→    };
   192→
   193→    Some(format!("{}{}{}", before, formatted_content, after))
   194→}
   195→
   196→/// Append a new section at the end of content.
   197→fn zvoff_append_section(content: &str, begin: &str, end: &str, new_content: &str) -> String {
   198→    let separator = if content.ends_with('\n') { "\n" } else { "\n\n" };
   199→
   200→    let formatted_content = if new_content.is_empty() {
   201→        format!("{}\n{}", begin, end)
   202→    } else if new_content.starts_with('\n') {
   203→        format!("{}{}\n{}", begin, new_content, end)
   204→    } else {
   205→        format!("{}\n{}\n{}", begin, new_content, end)
   206→    };
   207→
   208→    format!("{}{}{}\n", content, separator, formatted_content)
   209→}
   210→
   211→/// Collapse a section to an UNINSTALLED marker.
   212→fn zvoff_collapse_to_uninstalled(content: &str, begin: &str, end: &str, uninstalled: &str) -> Option<String> {
   213→    let begin_pos = content.find(begin)?;
   214→    let end_pos = content.find(end)?;
   215→
   216→    if end_pos <= begin_pos {
   217→        return None;
   218→    }
   219→
   220→    let before = &content[..begin_pos];
   221→    let after = &content[end_pos + end.len()..];
   222→
   223→    Some(format!("{}{}{}", before, uninstalled, after))
   224→}
   225→
   226→/// Parse a BEGIN marker and extract the tag.
   227→fn zvoff_parse_begin_marker(line: &str) -> Option<String> {
   228→    let trimmed = line.trim();
   229→    if trimmed.starts_with("<!-- MANAGED:") && trimmed.ends_with(":BEGIN -->") {
   230→        let inner = &trimmed[13..trimmed.len() - 10];
   231→        Some(inner.to_string())
   232→    } else {
   233→        None
   234→    }
   235→}
   236→
   237→/// Parse an END marker and extract the tag.
   238→fn zvoff_parse_end_marker(line: &str) -> Option<String> {
   239→    let trimmed = line.trim();
   240→    if trimmed.starts_with("<!-- MANAGED:") && trimmed.ends_with(":END -->") {
   241→        let inner = &trimmed[13..trimmed.len() - 8];
   242→        Some(inner.to_string())
   243→    } else {
   244→        None
   245→    }
   246→}
   247→
   248→/// Parse an UNINSTALLED marker and extract the tag.
   249→fn zvoff_parse_uninstalled_marker(line: &str) -> Option<String> {
   250→    let trimmed = line.trim();
   251→    if trimmed.starts_with("<!-- MANAGED:") && trimmed.ends_with(":UNINSTALLED -->") {
   252→        let inner = &trimmed[13..trimmed.len() - 16];
   253→        Some(inner.to_string())
   254→    } else {
   255→        None
   256→    }
   257→}
