   295→/// Collect Claude config assets for a single kit.
   296→/// Scans .claude/commands/ and .claude/hooks/ at kit forge root for cipher-matched files.
   297→/// Uses CWD as kit forge root (commands run from project root per launcher convention).
   298→/// Returns (commands_collected, hooks_collected).
   299→fn zvofr_collect_claude_assets(
   300→    _kit_forge: &Path,
   301→    staging: &Path,
   302→    cipher: &str,
   303→) -> Result<(u32, u32), String> {
   304→    let mut commands_count = 0u32;
   305→    let mut hooks_count = 0u32;
   306→
   307→    // Kit forge root is CWD (launcher cd's to project root before execution)
   308→    let kit_forge_root = Path::new(".");
   309→
   310→    // Collect commands from .claude/commands/
   311→    let commands_source = kit_forge_root.join(".claude").join("commands");
   312→    if commands_source.exists() {
   313→        let commands_dest = staging.join("claude").join("commands");
   314→        fs::create_dir_all(&commands_dest)
   315→            .map_err(|e| format!("Failed to create claude/commands dir: {}", e))?;
   316→
   317→        commands_count = zvofr_copy_matching_files(&commands_source, &commands_dest, cipher, true)?;
   318→    }
   319→
   320→    // Collect hooks from .claude/hooks/
   321→    let hooks_source = kit_forge_root.join(".claude").join("hooks");
   322→    if hooks_source.exists() {
   323→        let hooks_dest = staging.join("claude").join("hooks");
   324→        fs::create_dir_all(&hooks_dest)
   325→            .map_err(|e| format!("Failed to create claude/hooks dir: {}", e))?;
   326→
   327→        hooks_count = zvofr_copy_matching_files(&hooks_source, &hooks_dest, cipher, false)?;
   328→    }
   329→
   330→    Ok((commands_count, hooks_count))
   331→}
   332→
   333→/// Copy files matching cipher pattern from source to dest.
   334→/// is_command determines whether to match commands (c-) or hooks (h-).
   335→/// Returns count of files copied.
   336→fn zvofr_copy_matching_files(
   337→    source_dir: &Path,
   338→    dest_dir: &Path,
   339→    cipher: &str,
   340→    is_command: bool,
   341→) -> Result<u32, String> {
   342→    let mut count = 0u32;
   343→
   344→    let entries = fs::read_dir(source_dir)
   345→        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
   346→
   347→    for entry in entries {
   348→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   349→        let path = entry.path();
   350→
   351→        if !path.is_file() {
   352→            continue;
   353→        }
   354→
   355→        let file_name = path
   356→            .file_name()
   357→            .and_then(|n| n.to_str())
   358→            .unwrap_or("");
   359→
   360→        let matches = if is_command {
   361→            zvofr_is_command_file(file_name, cipher)
   362→        } else {
   363→            zvofr_is_hook_file(file_name, cipher)
   364→        };
   365→
   366→        if matches {
   367→            let dest_path = dest_dir.join(file_name);
   368→            fs::copy(&path, &dest_path)
   369→                .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
   370→            count += 1;
   371→        }
   372→    }
   373→
   374→    Ok(count)
   375→}
   376→
   377→/// Walk directory recursively, returning all file paths.
   378→fn zvofr_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
   379→    let mut files = Vec::new();
   380→
   381→    if !dir.is_dir() {
   382→        return Ok(files);
   383→    }
   384→
   385→    let entries = fs::read_dir(dir)
   386→        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
   387→
   388→    for entry in entries {
   389→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   390→        let path = entry.path();
   391→
   392→        if path.is_dir() {
   393→            files.extend(zvofr_walk_dir(&path)?);
   394→        } else {
   395→            files.push(path);
   396→        }
   397→    }
   398→
   399→    Ok(files)
   400→}
   401→
   402→/// Check if path is within vov_veiled/ directory.
   403→fn zvofr_is_veiled_path(rel_path: &Path) -> bool {
   404→    for component in rel_path.components() {
   405→        if let std::path::Component::Normal(name) = component {
   406→            if name == "vov_veiled" {
   407→                return true;
   408→            }
   409→        }
   410→    }
   411→    false
   412→}
