   262→/// Find a cipher by prefix.
   263→pub fn vofc_find_by_prefix(prefix: &str) -> Option<&'static vofc_Cipher> {
   264→    ALL_CIPHERS.iter().find(|c| c.prefix == prefix)
   265→}
   266→
   267→/// Check if a prefix is registered.
   268→pub fn vofc_is_registered(prefix: &str) -> bool {
   269→    vofc_find_by_prefix(prefix).is_some()
   270→}
   271→
   272→/// Validate terminal exclusivity: ensure no prefix is a prefix of another.
   273→/// Returns None if valid, or Some pair of conflicting ciphers.
   274→pub fn vofc_validate_terminal_exclusivity() -> Option<(&'static vofc_Cipher, &'static vofc_Cipher)> {
   275→    for (i, a) in ALL_CIPHERS.iter().enumerate() {
   276→        for b in ALL_CIPHERS.iter().skip(i + 1) {
   277→            if a.prefix.starts_with(b.prefix) || b.prefix.starts_with(a.prefix) {
   278→                return Some((a, b));
   279→            }
   280→        }
   281→    }
   282→    None
   283→}
