   175→#[tokio::main]
   176→async fn main() -> ExitCode {
   177→    let cli = Cli::parse();
   178→
   179→    let exit_code = match cli.command {
   180→        Some(Commands::Guard(args)) => run_guard(args),
   181→        Some(Commands::VvxCommit(args)) => run_commit(args),
   182→        Some(Commands::VvxInvitatory) => run_invitatory().await,
   183→        Some(Commands::VvxPush(args)) => run_push(args),
   184→        Some(Commands::VvxUnlock) => run_unlock(),
   185→        Some(Commands::ReleaseCollect(args)) => run_release_collect(args),
   186→        Some(Commands::ReleaseBrand(args)) => run_release_brand(args),
   187→        Some(Commands::VvxEmplace(args)) => run_emplace(args),
   188→        Some(Commands::VvxVacate(args)) => run_vacate(args),
   189→        Some(Commands::External(args)) => dispatch_external(args).await,
   190→        None => {
   191→            use clap::CommandFactory;
   192→            Cli::command().print_help().ok();
   193→            0
   194→        }
   195→    };
   196→
   197→    ExitCode::from(exit_code as u8)
   198→}
