   233→/// Dispatch external subcommands to appropriate kit CLIs
   234→async fn dispatch_external(args: Vec<OsString>) -> i32 {
   235→    if args.is_empty() {
   236→        eprintln!("vvx: error: no subcommand provided");
   237→        return 1;
   238→    }
   239→
   240→    let cmd_name = args[0].to_string_lossy();
   241→
   242→    // Delegate to JJK if available and command matches
   243→    #[cfg(feature = "jjk")]
   244→    if jjk::jjrx_is_jjk_command(&cmd_name) {
   245→        return jjk::jjrx_dispatch(&args).await;
   246→    }
   247→
   248→    // Unknown external subcommand
   249→    eprintln!("vvx: error: unknown command '{}'", cmd_name);
   250→    eprintln!("Run 'vvx --help' for available commands");
   251→    1
   252→}
