   254→/// Lock reference path for push operations (same as commit to prevent concurrent ops)
   255→const LOCK_REF: &str = "refs/vvg/locks/vvx";
   256→
   257→/// Force-break a stuck lock
   258→fn run_unlock() -> i32 {
   259→    use std::process::Command;
   260→
   261→    // Check if lock exists
   262→    let check = Command::new("git")
   263→        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
   264→        .status();
   265→
   266→    match check {
   267→        Ok(status) if status.success() => {
   268→            // Lock exists, delete it
   269→            let delete = Command::new("git")
   270→                .args(["update-ref", "-d", LOCK_REF])
   271→                .output();
   272→
   273→            match delete {
   274→                Ok(output) if output.status.success() => {
   275→                    eprintln!("unlock: lock broken successfully");
   276→                    0
   277→                }
   278→                Ok(output) => {
   279→                    eprintln!("unlock: error: failed to delete lock: {}",
   280→                        String::from_utf8_lossy(&output.stderr));
   281→                    1
   282→                }
   283→                Err(e) => {
   284→                    eprintln!("unlock: error: {}", e);
   285→                    1
   286→                }
   287→            }
   288→        }
   289→        Ok(_) => {
   290→            // Lock doesn't exist
   291→            eprintln!("unlock: no lock held");
   292→            0
   293→        }
   294→        Err(e) => {
   295→            eprintln!("unlock: error checking lock: {}", e);
   296→            1
   297→        }
   298→    }
   299→}
