   301→fn run_push(args: PushArgs) -> i32 {
   302→    use std::process::Command;
   303→
   304→    eprintln!("push: acquiring lock...");
   305→    let head_output = Command::new("git")
   306→        .args(["rev-parse", "HEAD"])
   307→        .output();
   308→
   309→    let lock_value = match head_output {
   310→        Ok(output) if output.status.success() => {
   311→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   312→        }
   313→        _ => "0000000000000000000000000000000000000000".to_string(),
   314→    };
   315→
   316→    let lock_result = Command::new("git")
   317→        .args(["update-ref", LOCK_REF, &lock_value, ""])
   318→        .output();
   319→
   320→    match lock_result {
   321→        Ok(output) if output.status.success() => {
   322→            // Lock acquired
   323→        }
   324→        _ => {
   325→            eprintln!("push: error: Another operation in progress - lock held");
   326→            return 1;
   327→        }
   328→    }
   329→
   330→    let result = run_push_workflow(&args);
   331→
   332→    let _ = Command::new("git")
   333→        .args(["update-ref", "-d", LOCK_REF])
   334→        .output();
   335→
   336→    match result {
   337→        Ok(()) => {
   338→            eprintln!("push: success");
   339→            0
   340→        }
   341→        Err(e) => {
   342→            eprintln!("push: error: {}", e);
   343→            1
   344→        }
   345→    }
   346→}
   347→
   348→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   349→    use std::process::Command;
   350→
   351→    let branch = match &args.branch {
   352→        Some(b) => b.clone(),
   353→        None => {
   354→            let output = Command::new("git")
   355→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   356→                .output()
   357→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   358→
   359→            if !output.status.success() {
   360→                return Err("Failed to determine current branch".to_string());
   361→            }
   362→
   363→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   364→        }
   365→    };
   366→
   367→    eprintln!("push: pushing {} to {}", branch, args.remote);
   368→
   369→    let mut push_args = vec!["push", &args.remote, &branch];
   370→    if args.force {
   371→        push_args.push("--force");
   372→    }
   373→
   374→    let output = Command::new("git")
   375→        .args(&push_args)
   376→        .output()
   377→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   378→
   379→    if !output.status.success() {
   380→        let stderr = String::from_utf8_lossy(&output.stderr);
   381→        return Err(format!("git push failed: {}", stderr));
   382→    }
   383→
   384→    Ok(())
   385→}
